import Link from 'next/link';
import { verifySession } from '@/lib/auth';
import { redirect } from 'next/navigation';
import CrmLogout from '@/components/CrmLogout';

export default async function CrmHomePage() {
  const ok = await verifySession();
  if (!ok) redirect('/crm/login');

  return (
    <div className="bg-white rounded-xl border border-gray-200 p-8 max-w-lg">
      <h1 className="text-xl font-bold text-primary mb-2">Staff area</h1>
      <p className="text-gray-600 text-sm mb-6">
        You&apos;re signed in. Add leads or other tools here when you wire them up.
      </p>
      <CrmLogout />
      <p className="mt-4 text-xs text-gray-400">
        <Link href="/" className="underline">
          ← Back to site
        </Link>
      </p>
    </div>
  );
}
